/**
 * Markdown → Telegram HTML 轉換器
 * 只處理 agent 常用的安全子集，避免 parse error。
 * code block 內不做任何二次轉換。
 */

function escHtml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");
}

/**
 * 把 agent 輸出的 Markdown 文字轉為 Telegram HTML。
 * 回傳 { html, plain }，plain 是純文字 fallback（已 escape）。
 */
export function markdownToHtml(text: string): { html: string; plain: string } {
  const lines = text.split("\n");
  const out: string[] = [];
  let inCode = false;
  let codeLang = "";
  const codeLines: string[] = [];

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];

    // Code block 開/關
    if (/^```/.test(line)) {
      if (!inCode) {
        inCode = true;
        codeLang = line.slice(3).trim();
        codeLines.length = 0;
      } else {
        // 閉合
        const cls = codeLang ? ` class="language-${escHtml(codeLang)}"` : "";
        out.push(`<pre><code${cls}>${escHtml(codeLines.join("\n"))}</code></pre>`);
        inCode = false;
        codeLang = "";
      }
      continue;
    }

    if (inCode) {
      codeLines.push(line);
      continue;
    }

    // 正常行：inline 轉換
    out.push(convertInline(line));
  }

  // 未閉合 code block → 當純文字 escape 輸出
  if (inCode) {
    out.push(`<pre><code>${escHtml(codeLines.join("\n"))}</code></pre>`);
  }

  const html = out.join("\n");
  return { html, plain: escHtml(text) };
}

/** 行內 Markdown → HTML（不處理巢狀） */
function convertInline(line: string): string {
  // blockquote
  if (/^>\s?/.test(line)) {
    const content = line.replace(/^>\s?/, "");
    return `<blockquote>${escHtml(content)}</blockquote>`;
  }

  let s = escHtml(line);

  // inline code（先處理，避免內容被其他 regex 改到）
  s = s.replace(/`([^`]+)`/g, "<code>$1</code>");

  // bold: **text** or __text__
  s = s.replace(/\*\*(.+?)\*\*/g, "<b>$1</b>");
  s = s.replace(/__(.+?)__/g, "<b>$1</b>");

  // italic: *text* or _text_ （排除已轉的 <b> 裡的底線）
  s = s.replace(/(?<![<\w])\*([^*]+)\*(?![>\w])/g, "<i>$1</i>");
  s = s.replace(/(?<![<\w])_([^_]+)_(?![>\w])/g, "<i>$1</i>");

  // strikethrough: ~~text~~
  s = s.replace(/~~(.+?)~~/g, "<s>$1</s>");

  // links: [text](url) — 需對已 escape 的文字處理
  s = s.replace(/\[([^\]]+)\]\(([^)]+)\)/g, '<a href="$2">$1</a>');

  return s;
}

