1	/**
2	 * Telegram UI helpers — message formatting, splitting, ASK keyboards,
3	 * file sending, and token extraction for SEND_FILE / SCHEDULE / ASK.
4	 * Extracted from index.ts to reduce its size.
5	 */
6	import { InlineKeyboard, Context, InputFile } from "grammy";
7	import path from "node:path";
8	import { stat } from "node:fs/promises";
9	import { config } from "./config.js";
10	import type { ChatSession } from "./sessionManager.js";
11	import { transform as transformReplyTokens } from "./observerTransformer.js";
12	import type { Recurrence } from "./recurrence.js";
13	import { markdownToHtml } from "./format-html.js";
14	
15	// ---------------------------------------------------------------------------
16	// Constants
17	// ---------------------------------------------------------------------------
18	const CODE_PLACEHOLDER_RE = /\u0000CODE(\d+)\u0000/g;
19	const SEND_FILE_RE = /<<SEND_FILE:\s*([^>\r\n]+?)\s*>>/g;
20	const SCHEDULE_RE = /<<SCHEDULE:\s*([^>\r\n]+?)\s*>>/g;
21	const SCHEDULE_PROMPT_MAX = 1000;
22	const SCHEDULE_MAX_PER_MSG = 3;
23	const ASK_RE = /<<ASK:\s*([^>\r\n]+?)\s*>>/g;
24	const ASK_ID_RE = /^[a-zA-Z0-9_-]{1,32}$/;
25	const ASK_KEY_RE = /^[a-zA-Z0-9_-]{1,20}$/;
26	const ASK_LABEL_MAX = 40;
27	const ASK_LABEL_SOFT = 20;
28	export const IMG_EXT = new Set([".png", ".jpg", ".jpeg", ".gif", ".webp", ".bmp"]);
29	export const TG_MAX = 3900;
30	
31	// ---------------------------------------------------------------------------
32	// Interfaces
33	// ---------------------------------------------------------------------------
34	export interface AskOption {
35	  key: string;
36	  label: string;
37	  recommended: boolean;
38	}
39	
40	export interface AskEntry {
41	  questionId: string;
42	  options: AskOption[];
43	}
44	
45	export interface ScheduleTokenEntry {
46	  runAt: number;
47	  prompt: string;
48	  whenLabel: string;
49	  recurrence?: Recurrence;
50	}
51	
52	export interface PendingSchedule {
53	  userId: number;
54	  kind: "add" | "at" | "every" | "daily";
55	  time: string;
56	  createdAt: number;
57	}
58	
59	/** Parsers injected by caller to avoid circular deps */
60	export interface ScheduleParsers {
61	  parseDuration: (s: string) => number | null;
62	  parseAbsoluteTime: (s: string) => Date | null;
63	  parseRecurrence: (s: string) => Recurrence | null;
64	  computeNextRunAt: (r: Recurrence, after: number) => number | null;
65	}
66	
67	// ---------------------------------------------------------------------------
68	// Code-block masking
69	// ---------------------------------------------------------------------------
70	export function maskCodeRegions(text: string): { masked: string; restore: (s: string) => string } {
71	  const slots: string[] = [];
72	  const masked = text.replace(/```[\s\S]*?```|`[^`\n]*`/g, (m) => {
73	    const idx = slots.length;
74	    slots.push(m);
75	    return `\u0000CODE${idx}\u0000`;
76	  });
77	  const restore = (s: string) =>
78	    s.replace(CODE_PLACEHOLDER_RE, (_m, i: string) => slots[Number(i)] ?? "");
79	  return { masked, restore };
80	}
81	
82	// ---------------------------------------------------------------------------
83	// SEND_FILE token extraction
84	// ---------------------------------------------------------------------------
85	export function extractSendFileTokens(text: string): { text: string; paths: string[] } {
86	  if (!text) return { text: "", paths: [] };
87	  const paths: string[] = [];
88	  const { masked, restore } = maskCodeRegions(text);
89	  const stripped = masked.replace(SEND_FILE_RE, (_m, p: string) => {
90	    paths.push(p.trim());
91	    return "";
92	  });
93	  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
94	  return { text: cleaned, paths };
95	}
96	
97	// ---------------------------------------------------------------------------
98	// SCHEDULE token extraction
99	// ---------------------------------------------------------------------------
100	export function extractScheduleTokens(
101	  text: string,
102	  parsers: ScheduleParsers,
103	): { text: string; entries: ScheduleTokenEntry[] } {
104	  if (!text) return { text: "", entries: [] };
105	  const entries: ScheduleTokenEntry[] = [];
106	  const { masked, restore } = maskCodeRegions(text);
107	  const stripped = masked.replace(SCHEDULE_RE, (match, inner: string) => {
108	    if (entries.length >= SCHEDULE_MAX_PER_MSG) return match;
109	    const pipe = inner.indexOf("|");
110	    if (pipe <= 0) return match;
111	    const timeRaw = inner.slice(0, pipe).trim();
112	    let prompt = inner.slice(pipe + 1).trim();
113	    if (!prompt) return match;
114	    if (prompt.length > SCHEDULE_PROMPT_MAX) {
115	      prompt = prompt.slice(0, SCHEDULE_PROMPT_MAX);
116	    }
117	    const now = Date.now();
118	    const recurrence = parsers.parseRecurrence(timeRaw);
119	    if (recurrence) {
120	      const firstRunAt = parsers.computeNextRunAt(recurrence, now - 1);
121	      if (firstRunAt === null) return match;
122	      entries.push({ runAt: firstRunAt, prompt, whenLabel: timeRaw, recurrence });
123	      return "";
124	    }
125	    let runAt: number | null = null;
126	    const dur = parsers.parseDuration(timeRaw);
127	    if (dur !== null) {
128	      runAt = now + dur;
129	    } else {
130	      const dt = parsers.parseAbsoluteTime(timeRaw);
131	      if (dt && dt.getTime() > now) runAt = dt.getTime();
132	    }
133	    if (runAt === null) return match;
134	    entries.push({ runAt, prompt, whenLabel: timeRaw });
135	    return "";
136	  });
137	  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
138	  return { text: cleaned, entries };
139	}
140	
141	// ---------------------------------------------------------------------------
142	// ASK token extraction & keyboard
143	// ---------------------------------------------------------------------------
144	export function extractAskTokens(text: string): { text: string; asks: AskEntry[] } {
145	  if (!text) return { text: "", asks: [] };
146	  const asks: AskEntry[] = [];
147	  const seenIds = new Set<string>();
148	  const { masked, restore } = maskCodeRegions(text);
149	  const stripped = masked.replace(ASK_RE, (match, inner: string) => {
150	    const entry = parseAskInner(inner);
151	    if (!entry) return match;
152	    if (seenIds.has(entry.questionId)) {
153	      const idx = asks.findIndex((a) => a.questionId === entry.questionId);
154	      if (idx >= 0) asks.splice(idx, 1);
155	    }
156	    seenIds.add(entry.questionId);
157	    asks.push(entry);
158	    return "";
159	  });
160	  const cleaned = restore(stripped).replace(/\n{3,}/g, "\n\n").trim();
161	  return { text: cleaned, asks };
162	}
163	
164	function parseAskInner(inner: string): AskEntry | null {
165	  const reject = (reason: string): null => {
166	    const preview = inner.length > 80 ? `${inner.slice(0, 77)}...` : inner;
167	    console.warn(`[ASK] malformed token rejected: ${reason} | inner="${preview}"`);
168	    return null;
169	  };
170	  const parts = inner.split("|").map((s) => s.trim());
171	  if (parts.length < 2) return reject("need at least question_id + 1 option");
172	  const questionId = parts[0];
173	  if (!ASK_ID_RE.test(questionId)) {
174	    return reject(
175	      `question_id "${questionId}" invalid (need [a-zA-Z0-9_-]{1,32}, got length ${questionId.length})`
176	    );
177	  }
178	  const options: AskOption[] = [];
179	  const keys = new Set<string>();
180	  let recommendedCount = 0;
181	  for (const raw of parts.slice(1)) {
182	    if (!raw) continue;
183	    let spec = raw;
184	    let recommended = false;
185	    if (spec.startsWith("*")) {
186	      recommended = true;
187	      spec = spec.slice(1);
188	    }
189	    const eq = spec.indexOf("=");
190	    if (eq <= 0) return reject(`option "${raw}" missing "key=label"`);
191	    const key = spec.slice(0, eq).trim();
192	    const label = spec.slice(eq + 1).trim();
193	    if (!ASK_KEY_RE.test(key)) {
194	      return reject(
195	        `key "${key}" invalid (need [a-zA-Z0-9_-]{1,20}, got length ${key.length})`
196	      );
197	    }
198	    if (!label) return reject(`key "${key}" has empty label`);
199	    if (label.length > ASK_LABEL_SOFT && label.length <= ASK_LABEL_MAX) {
200	      console.warn(
201	        `[ASK] label soft cap exceeded (got ${label.length}, soft ${ASK_LABEL_SOFT}): key="${key}" label="${label}"`,
202	      );
203	    }
204	    if (label.length > ASK_LABEL_MAX) {
205	      return reject(
206	        `key "${key}" label too long (got ${label.length}, max ${ASK_LABEL_MAX}): "${label}"`
207	      );
208	    }
209	    if (keys.has(key)) return reject(`duplicate key "${key}"`);
210	    keys.add(key);
211	    if (recommended && recommendedCount > 0) recommended = false;
212	    if (recommended) recommendedCount++;
213	    options.push({ key, label, recommended });
214	  }
215	  if (options.length < 1) return reject("no valid options");
216	  if (options.length > 8) return reject(`too many options (got ${options.length}, max 8)`);
217	  return { questionId, options };
218	}
219	
220	export function buildAskKeyboard(asks: AskEntry[]): InlineKeyboard | null {
221	  if (!asks.length) return null;
222	  const kb = new InlineKeyboard();
223	  for (let ai = 0; ai < asks.length; ai++) {
224	    const entry = asks[ai];
225	    const rows = layoutOptions(entry.options);
226	    for (const row of rows) {
227	      for (const opt of row) {
228	        const label = opt.recommended ? `⭐ ${opt.label}` : opt.label;
229	        kb.text(label, `A:${entry.questionId}:${opt.key}`);
230	      }
231	      kb.row();
232	    }
233	    const rec = entry.options.find((o) => o.recommended);
234	    if (rec) {
235	      kb.text("👉 照你的建議", `A:${entry.questionId}:${rec.key}`).row();
236	    }
237	  }
238	  return kb;
239	}
240	
241	export function layoutOptions(options: AskOption[]): AskOption[][] {
242	  const n = options.length;
243	  if (n <= 3) return [options];
244	  if (n <= 6) {
245	    const perRow = Math.ceil(n / 2);
246	    return [options.slice(0, perRow), options.slice(perRow)];
247	  }
248	  const perRow = Math.ceil(n / 2);
249	  return [options.slice(0, perRow), options.slice(perRow)];
250	}
251	
252	// In-memory registry: message_id -> ASK entries on that message.
253	export const askRegistry = new Map<number, AskEntry[]>();
254	
255	export async function replyWithAsk(ctx: Context, text: string): Promise<void> {
256	  const { text: displayBody, asks } = extractAskTokens(text);
257	  const body = displayBody || text;
258	  const keyboard = buildAskKeyboard(asks);
259	  const msg = await ctx.reply(body, keyboard ? { reply_markup: keyboard } : {});
260	  if (keyboard && msg?.message_id !== undefined) {
261	    askRegistry.set(msg.message_id, asks);
262	  }
263	}
264	
265	// ---------------------------------------------------------------------------
266	// askTimeKeyToWire / describePendingSchedule
267	// ---------------------------------------------------------------------------
268	export function askTimeKeyToWire(kind: PendingSchedule["kind"], key: string): string | null {
269	  if (kind === "add" || kind === "every") {
270	    return /^\d+(s|m|h|d)$/.test(key) ? key : null;
271	  }
272	  const mDirect = /^(\d{2})(\d{2})$/.exec(key);
273	  if (mDirect) return `${mDirect[1]}:${mDirect[2]}`;
274	  if (kind === "at") {
275	    const mTmr = /^tmr_(\d{2})(\d{2})$/.exec(key);
276	    if (mTmr) return `tomorrow ${mTmr[1]}:${mTmr[2]}`;
277	  }
278	  return null;
279	}
280	
