57	// ─── Sticker auto-selection ──────────────────────────────────────────────────
58	
59	const EMOTION_REPRS: Record<string, string> = {
60	  hello: "打招呼 你好 嗨 早安 晚安 greeting",
61	  happy: "開心 太好了 成功 完成了 恭喜 great",
62	  thanks: "謝謝 感謝 thank you 不客氣",
63	  sorry: "抱歉 對不起 不好意思 sorry",
64	  agree: "同意 沒問題 好的 了解 ok sure",
65	  good: "做得好 讚 很棒 nice well done",
66	  clap: "恭喜 太厲害了 完美 bravo",
67	  love: "喜歡 愛 太棒了 超讚",
68	  sad: "可惜 遺憾 不幸 unfortunately",
69	  shock: "驚訝 天啊 沒想到 wow unexpected",
70	  ok: "收到 了解 知道了 acknowledged",
71	};
72	const STICKER_AUTO_THRESHOLD = 0.65;
73	const STICKER_AUTO_MAX_REPLY_LEN = 150;
74	let emotionVectors: Map<string, Float32Array> | null = null;
75	
76	export async function autoSelectSticker(reply: string): Promise<string | null> {
77	  if (reply.length > STICKER_AUTO_MAX_REPLY_LEN || reply.length < 5) return null;
78	  if (!emotionVectors) {
79	    emotionVectors = new Map();
80	    for (const [emotion, repr] of Object.entries(EMOTION_REPRS)) {
81	      const vec = await embedText(repr);
82	      if (vec) emotionVectors.set(emotion, vec);
83	    }
84	  }
85	  const queryVec = await embedText(reply);
86	  if (!queryVec) return null;
87	  let best = "";
88	  let bestScore = 0;
89	  for (const [emotion, vec] of emotionVectors) {
90	    const score = cosineSim(queryVec, vec);
91	    if (score > bestScore) { bestScore = score; best = emotion; }
92	  }
93	  return bestScore >= STICKER_AUTO_THRESHOLD ? best : null;
94	}
