135	// ─── Auto-wikilink post-processing ───────────────────────────────────────────
136	
137	/** After a wiki page is written, scan it and inject [[wikilinks]] for known entities. */
138	function applyAutoWikilink(slug: string): void {
139	  const { MEMORY_DIR } = deps();
140	  for (const sub of ["queries", "concepts", "references", "lessons", "tasks"]) {
141	    const filePath = path.join(MEMORY_DIR, "wiki", sub, `${slug}.md`);
142	    if (existsSync(filePath)) {
143	      try {
144	        const content = readFileSync(filePath, "utf8");
145	        const linked = autoWikilink(content);
146	        if (linked !== content) {
147	          writeFileSync(filePath, linked, "utf8");
148	          console.log(`[auto-wikilink] injected links into wiki/${sub}/${slug}.md`);
149	        }
150	      } catch (err) {
151	        console.error(`[auto-wikilink] failed for ${slug}:`, err);
152	      }
153	      return;
154	    }
155	  }
156	}
