158	// ─── runPrompt ────────────────────────────────────────────────────────────────
159	
160	export async function runPrompt(
161	  ctx: Context,
162	  session: ChatSession,
163	  text: string,
164	  mode: RunPromptMode = { kind: "user" },
165	) {
166	  const { bot, sessions, rateLimitedUntil, onRateLimitRecovery, queuePendingMessage,
167	    handleRestart, STREAM_EDIT_INTERVAL_MS, MEMORY_DIR, scheduler, scheduleStore } = deps();
168	
169	  const continuationContext: ContinuationContext | undefined =
170	    mode.kind === "continuation" ? mode.context : undefined;
171	  const isMeta = mode.kind === "meta";
172	  const isSilentMeta = mode.kind === "meta" && mode.silent === true;
173	  const relayReplyTo = mode.kind === "relay" ? mode.replyTo : undefined;
174	  const isRelay = mode.kind === "relay";
175	  const chatId = ctx.chat!.id;
176	
177	  // Guard against concurrent prompts on the same ACP session.
178	  if (session.inflight) {
179	    if (relayReplyTo) {
180	      sendRelay(relayReplyTo, "小X 目前上一輪還在處理中，稍後再回覆。").catch((err) =>
181	        console.error(`[chat ${chatId}] relay busy notice to ${relayReplyTo} failed:`, err),
182	      );
183	      notifyRelayOwner(
184	        bot,
185	        config.allowedUserIds[0] ?? 0,
186	        `⏳ 「${relayReplyTo}」又送來 relay 訊息，但上一輪還在處理中，已擋掉這次重複注入。`,
187	        `busy notice for ${relayReplyTo}`,
188	      );
189	      return;
190	    }
191	    if (isMeta) {
192	      console.log(`[chat ${chatId}] meta prompt queued (session inflight)`);
193	      session._pendingMetaQueue.push({ ctx: ctx as unknown as any, prompt: text, opts: mode as any });
194	      return;
195	    }
196	    await ctx.reply(
197	      "⏳ 上一個回合還在進行中。請等它結束，或先用 /cancel 取消。",
198	    );
199	    return;
200	  }
201	  session.inflight = true;
202	  sessions.resetTurn(session);
203	  petState("thinking");
204	
205	  let continuationPlan: ContinuationPlan | null = null;
206	  let continueTokenFired = false;
207	  let pendingRestartReason: string | null = null;
208	
209	  if (!continuationContext) {
210	    session.history.push({ role: "user", text, timestamp: Date.now() });
211	  }
212	  session.charsIn += text.length;
213	
214	  let promptText = text;
215	  if (!session.preambleInjected && session.memoryPreamble) {
216	    promptText = session.memoryPreamble + text;
217	    session.preambleInjected = true;
218	  }
219	
220	  const replyToId = ctx.message?.message_id;
221	  const placeholderText = continuationContext
222	    ? `↻ Continuing (${continuationContext.turnIndex}/${continuationContext.maxTurns}) toward goal…`
223	    : "Thinking…";
224	  let placeholder: { message_id: number } | undefined;
225	  if (!isRelay && !isSilentMeta) {
226	    try {
227	      placeholder = await ctx.reply(placeholderText, {
228	        ...(replyToId ? { reply_parameters: { message_id: replyToId } } : {}),
229	      });
230	    } catch (err: any) {
231	      const desc = err?.description || err?.error?.description || "";
232	      if (replyToId && /message to be replied not found/i.test(desc)) {
233	        placeholder = await ctx.reply(placeholderText);
234	      } else {
235	        throw err;
236	      }
237	    }
238	  }
239	
240	  let lastEditAt = 0;
241	  let lastRendered = "";
242	  let editTimer: NodeJS.Timeout | null = null;
243	  let throttledSnapshotLogged = false;
244	  let turnHitRateLimit = false;
245	  let turnFinalized = false;
246	
247	  const editNow = async () => {
248	    if (!placeholder) return;
249	    if (rateLimitedUntil() > Date.now()) {
250	      turnHitRateLimit = true;
251	      if (!throttledSnapshotLogged) {
252	        throttledSnapshotLogged = true;
253	        const snapshot = (session.buffer || "").trim();
254	        const preview = snapshot.length > 800
255	          ? snapshot.slice(0, 800) + `…[+${snapshot.length - 800} chars]`
256	          : snapshot;
257	        console.warn(
258	          `[rate-limit] chat ${chatId} streaming paused; current buffer (${snapshot.length} chars):\n---\n${preview || "(empty)"}\n---`
259	        );
260	      }
261	      return;
262	    }
263	    const { content, parseMode } = renderReply(session, false, scheduleParsers);
264	    if (content === lastRendered) return;
265	    lastRendered = content;
266	    lastEditAt = Date.now();
267	    try {
268	      await ctx.api.editMessageText(chatId, placeholder.message_id, content,
269	        parseMode ? { parse_mode: parseMode } : {});
270	    } catch {
271	      // parse error or identical content — retry without parse_mode (strip HTML tags)
272	      try {
273	        await ctx.api.editMessageText(chatId, placeholder.message_id,
274	          content.replace(/<[^>]+>/g, ""));
275	      } catch { /* identical or rate-limited; ignore */ }
276	    }
277	  };
278	
279	  const unregisterRecovery = isRelay || isSilentMeta ? () => {} : onRateLimitRecovery(() => {
280	    if (turnFinalized) {
281	      console.log(
282	        `[rate-limit] chat ${chatId} recovery callback suppressed — turn already finalized`
283	      );
284	      return;
285	    }
286	    throttledSnapshotLogged = false;
287	    console.log(
288	      `[rate-limit] chat ${chatId} resuming edits — pushing latest buffer (${(session.buffer || "").length} chars)`
289	    );
290	    lastRendered = "";
291	    return editNow();
292	  });
293	
294	  session.onUpdate = isRelay
295	    ? undefined
296	    : () => {
297	        const elapsed = Date.now() - lastEditAt;
298	        if (elapsed >= STREAM_EDIT_INTERVAL_MS) {
299	          editNow();
300	        } else if (!editTimer) {
301	          editTimer = setTimeout(() => {
302	            editTimer = null;
303	            editNow();
304	          }, STREAM_EDIT_INTERVAL_MS - elapsed);
305	        }
306	      };
307	
308	
309	  try {
310	    const { stopReason } = await session.client.prompt(promptText);
311	    if (editTimer) {
312	      clearTimeout(editTimer);
313	      editTimer = null;
314	    }
315	    turnFinalized = true;
316	
317	    if (session.buffer) {
318	      session.history.push({ role: "assistant", text: session.buffer, timestamp: Date.now() });
319	    }
320	
321	    const toolsPrefix = session.toolLog.length
322	      ? session.toolLog.slice(-5).join("\n") + "\n\n"
323	      : "";
324	
325	    // Extract relay tokens before ab7 (it doesn't know them).
326	    const relayTokens: { target: string; text: string }[] = [];
327	    const relayFileTokens: { target: string; path: string }[] = [];
328	    const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];
329	    const relayResultTokens: { target: string; payload: ResultPayload }[] = [];
330	    const parallelDelegateTasks: ParallelTask[] = [];
331	    const RELAY_RE = /<<RELAY:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
332	    const RELAY_FILE_RE = /<<RELAY_FILE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
333	    const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
334	    const RELAY_RESULT_RE = /<<RELAY_RESULT:\s*([^|>\r\n]+?)\s*\|\s*(\{[^>\r\n]+?\})\s*>>/g;
335	    const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
336	    {
337	      const { masked, restore } = maskCodeRegions(session.buffer);
338	      const stripped = masked
339	        .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {
340	          let p: DelegatePayload;
341	          try {
342	            p = JSON.parse(body) as DelegatePayload;
343	            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
344	          } catch {
345	            p = { id: `rd_${Date.now()}`, goal: body.trim() };
346	          }
347	          if (p.goal) relayDelegateTokens.push({ target: target.trim(), payload: p });
348	          return "";
349	        })
350	        .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {
351	          try {
352	            const p = JSON.parse(json) as ResultPayload;
353	            relayResultTokens.push({ target: target.trim(), payload: p });
354	          } catch { /* malformed JSON — ignore */ }
355	          return "";
356	        })
357	        .replace(RELAY_RE, (_m, target: string, msg: string) => {
358	          relayTokens.push({ target: target.trim(), text: msg.trim() });
359	          return "";
360	        })
361	        .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {
362	          relayFileTokens.push({ target: target.trim(), path: p.trim() });
363	          return "";
364	        })
365	        .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {
366	          parallelDelegateTasks.push({
367	            taskId: taskId.trim(),
368	            target: target.trim(),
369	            payload: { id: taskId.trim(), goal: prompt.trim() },
370	          });
371	          return "";
372	        });
373	      session.buffer = restore(stripped);
374	    }
375	
376	    // Fallback: recover RELAY_DELEGATE from streaming captures
377	    if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {
378	      const RELAY_DELEGATE_RE2 = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
379	      for (const raw of session._streamingDelegates) {
380	        RELAY_DELEGATE_RE2.lastIndex = 0;
381	        const m = RELAY_DELEGATE_RE2.exec(raw);
382	        if (m) {
383	          let p: DelegatePayload;
384	          try {
385	            p = JSON.parse(m[2]) as DelegatePayload;
386	            if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
387	          } catch {
388	            p = { id: `rd_${Date.now()}`, goal: m[2].trim() };
389	          }
390	          if (p.goal) relayDelegateTokens.push({ target: m[1].trim(), payload: p });
391	        }
392	      }
393	      if (relayDelegateTokens.length > 0) {
394	        console.log(`[chat ${chatId}] relay delegate recovered from streaming capture (${relayDelegateTokens.length} token(s))`);
395	      }
396	    }
397	
398	    // <<RELAY_DONE>>
399	    const { masked: maskedForDone, restore: restoreDone } = maskCodeRegions(session.buffer);
400	    const relayDone = /<<RELAY_DONE>>/i.test(maskedForDone);
401	    if (relayDone) {
402	      session.buffer = restoreDone(maskedForDone.replace(/<<RELAY_DONE>>/gi, "").trim());
403	      if (relayReplyTo) getRelayLoopGuard()?.markDone(relayReplyTo);
404	    }
405	
406	    const ab7 = transformReplyTokens(session.buffer, {
407	      parseDuration,
408	      parseAbsoluteTime,
409	      parseRecurrence,
410	      computeNextRunAt,
411	    });
412	
413	    // SKILL_USED → usageStore
414	    if (ab7.skillUsages.length > 0) {
415	      const skillDir = detectSkillDir();
416	      if (!skillDir.startsWith("(")) {
417	        for (const u of ab7.skillUsages) {
418	          usageStore.markUsed(skillDir, u.name, u.reason).catch((err) => {
419	            console.error(`[chat ${chatId}] usageStore.markUsed(${u.name}) failed:`, err);
420	          });
421	        }
422	      } else {
423	        console.warn(`[chat ${chatId}] SKILL_USED tokens seen but SKILL_DIR unresolved: ${skillDir}`);
424	      }
425	    }
426	
427	
428	    // ─── Goal bookkeeping ─────────────────────────────────────────────────────
429	    let goalAchievementLine: string | null = null;
430	    if (isMeta) {
431	      // no-op: meta turns bypass all goal bookkeeping
432	    } else if (ab7.goalDone) {
433	      try {
434	        const wasActive = await goalStore.isActive(config.memoryDir, chatId);
435	        if (wasActive) {
436	          const s = await goalStore.markDone(config.memoryDir, chatId, ab7.goalDone.reason);
437	          goalAchievementLine = `\n\n✓ Goal achieved: ${s.last_reason}`;
438	        } else {
439	          console.warn(`[chat ${chatId}] GOAL_DONE ignored: no active goal (reason="${ab7.goalDone.reason}")`);
440	        }
441	      } catch (err) {
442	        console.error(`[chat ${chatId}] goalStore.markDone failed:`, err);
443	      }
444	    } else if (!continuationContext) {
445	      try {
446	        const gs = await goalStore.get(config.memoryDir, chatId);
447	        if (gs && gs.status === "active") {
448	          const result = await goalStore.incrementTurn(config.memoryDir, chatId, session.buffer ? session.buffer.slice(0, 200) : undefined);
449	          if (result.pausedByBudget) {
450	            const reflection = `Budget exhausted (${result.state.turns_used}/${result.state.max_turns}) without achieving goal. Last output: ${(session.buffer || "").slice(0, 200)}`;
451	            const retryResult = await goalStore.markReflectionRetry(config.memoryDir, chatId, reflection);
452	            if (retryResult.ok) {
453	              console.log(`[chat ${chatId}] goal reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX}`);
454	              continuationPlan = {
455	                turnIndex: 1,
456	                maxTurns: retryResult.state.max_turns,
457	                objective: retryResult.state.objective,
458	                lastReason: `[Reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX}] Previous attempt failed to achieve the goal. Reflect: what went wrong? Try a different approach.\n${reflection}`,
459	              };
460	            } else {
461	              goalAchievementLine = `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used, ${result.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} retries exhausted. /goal resume 續跑；/goal clear 放棄。`;
462	            }
463	          } else {
464	            continuationPlan = {
465	              turnIndex: result.state.turns_used + 1,
466	              maxTurns: result.state.max_turns,
467	              objective: result.state.objective,
468	              lastReason: result.state.last_reason,
469	            };
470	          }
471	        }
472	      } catch (err) {
473	        console.error(`[chat ${chatId}] AB-7b continuation planning failed:`, err);
474	      }
475	    } else {
476	      // Already in a continuation turn — check budget again.
477	      try {
478	        const gs = await goalStore.get(config.memoryDir, chatId);
479	        if (gs && gs.status === "active") {
480	          const result = await goalStore.incrementTurn(config.memoryDir, chatId, session.buffer ? session.buffer.slice(0, 200) : undefined);
481	          if (result.pausedByBudget) {
482	            const reflection = `Budget exhausted (${result.state.turns_used}/${result.state.max_turns}) without achieving goal. Last output: ${(session.buffer || "").slice(0, 200)}`;
483	            const retryResult = await goalStore.markReflectionRetry(config.memoryDir, chatId, reflection);
484	            if (retryResult.ok) {
485	              console.log(`[chat ${chatId}] goal reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} (continuation path)`);
486	              continuationPlan = {
487	                turnIndex: 1,
488	                maxTurns: retryResult.state.max_turns,
489	                objective: retryResult.state.objective,
490	                lastReason: `[Reflection retry ${retryResult.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX}] Previous attempt failed to achieve the goal. Reflect: what went wrong? Try a different approach.\n${reflection}`,
491	              };
492	            } else {
493	              goalAchievementLine = `\n\n⏸ Goal paused — ${result.state.turns_used}/${result.state.max_turns} turns used, ${result.state.reflection_retries}/${goalStore.GOAL_REFLECTION_MAX} retries exhausted. /goal resume 續跑；/goal clear 放棄。`;
494	            }
495	          } else {
496	            continuationPlan = {
497	              turnIndex: result.state.turns_used + 1,
498	              maxTurns: result.state.max_turns,
499	              objective: result.state.objective,
500	              lastReason: result.state.last_reason,
501	            };
502	          }
503	        }
504	      } catch (err) {
505	        console.error(`[chat ${chatId}] AB-7b continuation re-plan failed:`, err);
506	      }
507	    }
508	
509	
510	    // ─── RESTART token ──────────────────────────────────────────────────────
511	    if (!isMeta && ab7.restartToken) {
512	      const requestedReason = ab7.restartToken.reason;
513	      if (ab7.goalDone) {
514	        console.warn(`[chat ${chatId}] RESTART ignored: GOAL_DONE present in same turn (restart reason="${requestedReason}")`);
515	      } else {
516	        try {
517	          const result = await goalStore.markRestart(config.memoryDir, chatId, requestedReason);
518	          if (result.ok || (!result.ok && (result.code === "no-goal" || result.code === "not-active" || result.code === "empty-reason"))) {
519	            pendingRestartReason = requestedReason;
520	            const countLine = result.ok
521	              ? `🔄 Agent 請求 bridge 重啟 (${result.state.restart_count}/${goalStore.GOAL_RESTART_CAP_PER_GOAL}): ${requestedReason}`
522	              : `🔄 Agent 請求 bridge 重啟: ${requestedReason}`;
523	            goalAchievementLine = goalAchievementLine
524	              ? `${goalAchievementLine}\n\n${countLine}`
525	              : `\n\n${countLine}`;
526	            if (continuationPlan) {
527	              console.log(`[chat ${chatId}] RESTART accepted: dropping pending continuationPlan (turn ${continuationPlan.turnIndex}/${continuationPlan.maxTurns}); post-restart auto-resume will re-fire it`);
528	              continuationPlan = null;
529	            }
530	          } else {
531	            const warnLine = `⚠️ RESTART 忽略 (${result.code}): ${result.message}`;
532	            goalAchievementLine = goalAchievementLine
533	              ? `${goalAchievementLine}\n\n${warnLine}`
534	              : `\n\n${warnLine}`;
535	            console.warn(`[chat ${chatId}] RESTART rejected: code=${result.code} reason="${requestedReason}" — ${result.message}`);
536	          }
