276	// ─── Relay token dispatch ───────────────────────────────────────────────────
277	
278	export interface RelayTokens {
279	  relayTokens: { target: string; text: string }[];
280	  relayFileTokens: { target: string; path: string }[];
281	  relayDelegateTokens: { target: string; payload: DelegatePayload }[];
282	  relayResultTokens: { target: string; payload: ResultPayload }[];
283	  parallelDelegateTasks: ParallelTask[];
284	}
285	
286	/**
287	 * Extract relay/delegate/parallel tokens from session buffer.
288	 * Mutates session.buffer to strip extracted tokens.
289	 */
290	export function extractRelayTokens(session: ChatSession): RelayTokens {
291	  const relayTokens: { target: string; text: string }[] = [];
292	  const relayFileTokens: { target: string; path: string }[] = [];
293	  const relayDelegateTokens: { target: string; payload: DelegatePayload }[] = [];
294	  const relayResultTokens: { target: string; payload: ResultPayload }[] = [];
295	  const parallelDelegateTasks: ParallelTask[] = [];
296	
297	  const RELAY_RE = /<<RELAY:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
298	  const RELAY_FILE_RE = /<<RELAY_FILE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
299	  const RELAY_DELEGATE_RE = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
300	  const RELAY_RESULT_RE = /<<RELAY_RESULT:\s*([^|>\r\n]+?)\s*\|\s*(\{[^>\r\n]+?\})\s*>>/g;
301	  const PARALLEL_DELEGATE_RE = /<<PARALLEL_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
302	
303	  const { masked, restore } = maskCodeRegions(session.buffer);
304	  const stripped = masked
305	    .replace(RELAY_DELEGATE_RE, (_m, target: string, body: string) => {
306	      let p: DelegatePayload;
307	      try {
308	        p = JSON.parse(body) as DelegatePayload;
309	        if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
310	      } catch {
311	        p = { id: `rd_${Date.now()}`, goal: body.trim() };
312	      }
313	      if (p.goal) relayDelegateTokens.push({ target: target.trim(), payload: p });
314	      return "";
315	    })
316	    .replace(RELAY_RESULT_RE, (_m, target: string, json: string) => {
317	      try {
318	        const p = JSON.parse(json) as ResultPayload;
319	        relayResultTokens.push({ target: target.trim(), payload: p });
320	      } catch { /* malformed JSON — ignore */ }
321	      return "";
322	    })
323	    .replace(RELAY_RE, (_m, target: string, msg: string) => {
324	      relayTokens.push({ target: target.trim(), text: msg.trim() });
325	      return "";
326	    })
327	    .replace(RELAY_FILE_RE, (_m, target: string, p: string) => {
328	      relayFileTokens.push({ target: target.trim(), path: p.trim() });
329	      return "";
330	    })
331	    .replace(PARALLEL_DELEGATE_RE, (_m, taskId: string, target: string, prompt: string) => {
332	      parallelDelegateTasks.push({
333	        taskId: taskId.trim(),
334	        target: target.trim(),
335	        payload: { id: taskId.trim(), goal: prompt.trim() },
336	      });
337	      return "";
338	    });
339	  session.buffer = restore(stripped);
340	
341	  // Fallback: streaming captures
342	  if (relayDelegateTokens.length === 0 && session._streamingDelegates?.length) {
343	    const RE2 = /<<RELAY_DELEGATE:\s*([^|>\r\n]+?)\s*\|\s*([^>\r\n]+?)\s*>>/g;
344	    for (const raw of session._streamingDelegates) {
345	      RE2.lastIndex = 0;
346	      const m = RE2.exec(raw);
347	      if (m) {
348	        let p: DelegatePayload;
349	        try {
350	          p = JSON.parse(m[2]) as DelegatePayload;
351	          if (!p.id && (p as any).correlationId) p.id = (p as any).correlationId;
352	        } catch {
353	          p = { id: `rd_${Date.now()}`, goal: m[2].trim() };
354	        }
355	        if (p.goal) relayDelegateTokens.push({ target: m[1].trim(), payload: p });
356	      }
357	    }
358	    if (relayDelegateTokens.length > 0) {
359	      console.log(`[relay] delegate recovered from streaming capture (${relayDelegateTokens.length} token(s))`);
360	    }
361	  }
362	
363	  return { relayTokens, relayFileTokens, relayDelegateTokens, relayResultTokens, parallelDelegateTasks };
364	}
365	
366	/**
367	 * Check and strip <<RELAY_DONE>> from session buffer.
368	 */
369	export function extractRelayDone(session: ChatSession, relayReplyTo: string | undefined): boolean {
370	  const { masked, restore } = maskCodeRegions(session.buffer);
371	  const done = /<<RELAY_DONE>>/i.test(masked);
372	  if (done) {
373	    session.buffer = restore(masked.replace(/<<RELAY_DONE>>/gi, "").trim());
374	    if (relayReplyTo) relayLoopGuard?.markDone(relayReplyTo);
375	  }
376	  return done;
377	}
