381	
382	export interface DispatchRelayOpts {
383	  chatId: number;
384	  ctx: Context;
385	  session: ChatSession;
386	  tokens: RelayTokens;
387	  relayReplyTo: string;
388	  relayDone: boolean;
389	  body: string;
390	  goalContinuationDelayMs: number;
391	}
