393	/**
394	 * Dispatch relay tokens in headless (relay-reply) mode.
395	 * Returns true if handled (caller should return early).
396	 */
397	export function dispatchRelayHeadless(opts: DispatchRelayOpts): boolean {
398	  const { chatId, tokens, relayReplyTo, relayDone, body, goalContinuationDelayMs, ctx, session } = opts;
399	  const { relayTokens, relayFileTokens, relayDelegateTokens, relayResultTokens } = tokens;
400	
401	  for (const rt of relayTokens) {
402	    sendRelay(rt.target, rt.text).catch((err) =>
403	      console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));
404	  }
405	  for (const rf of relayFileTokens) {
406	    sendRelayFile(rf.target, rf.path, "[RELAY_OUTPUT]").catch((err) =>
407	      console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));
408	  }
409	  for (const rd of relayDelegateTokens) {
410	    sendRelayDelegate(rd.target, rd.payload).catch((err) =>
411	      console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));
412	  }
413	  for (const rr of relayResultTokens) {
414	    sendRelayResult(rr.target, rr.payload).catch((err) =>
415	      console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));
416	    relayLoopGuard?.markDone(rr.target);
417	  }
418	
419	  const sentExplicitReply = relayTokens.some((rt) => rt.target === relayReplyTo) ||
420	    relayResultTokens.some((rr) => rr.target === relayReplyTo);
421	  const shouldSendAutoReply = !sentExplicitReply && body.trim() !== "" && !relayDone;
422	  if (shouldSendAutoReply) {
423	    sendRelay(relayReplyTo, body).catch((err) =>
424	      console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));
425	  }
426	
427	  console.log(
428	    `[chat ${chatId}] relay reply delivered headlessly to ${relayReplyTo} ` +
429	      `(bufferChars=${session.buffer.length}${relayDone ? ", RELAY_DONE" : ""}, autoReply=${shouldSendAutoReply})`,
430	  );
431	
432	  if (relayDone) {
433	    const peer = relayReplyTo;
434	    const privateChatId = config.allowedUserIds[0] ?? 0;
435	    if (privateChatId) {
436	      ctx.api.sendMessage(privateChatId, `✅ 與「${peer}」的 relay 對話結束`).catch(() => {});
437	    }
438	    const { runPrompt, sessions } = deps();
439	    setTimeout(() => {
440	      const summaryPrompt =
441	        `[系統] 你剛才與「${peer}」的 relay 對話已結束。` +
442	        `請用一句話摘要這次 relay 對話的重點，然後呼叫 remember() 存下來。` +
443	        `格式範例：remember("[relay ${peer}] …摘要內容…")。` +
444	        `不需要回覆其他內容。`;
445	      runPrompt(ctx, session, summaryPrompt, { kind: "meta", silent: true }).catch((err) => {
446	        console.error(`[chat ${chatId}] relay summary meta prompt failed:`, err);
447	      });
448	    }, goalContinuationDelayMs);
449	  }
450	
451	  return true;
452	}
