468	/**
469	 * Dispatch relay tokens in visible (user-facing) mode.
470	 * Fire-and-forget — does not block the reply render.
471	 */
472	export function dispatchRelayVisible(opts: DispatchRelayVisibleOpts): void {
473	  const { chatId, bot, ctx, session, tokens, relayReplyTo, relayDone, body } = opts;
474	  const { relayTokens, relayFileTokens, relayDelegateTokens, relayResultTokens } = tokens;
475	
476	  if (relayDone) return; // already handled by extractRelayDone
477	
478	  if (relayTokens.length > 0) console.log(`[chat ${chatId}] relay tokens parsed: ${relayTokens.map(t => t.target).join(", ")}`);
479	  for (const rt of relayTokens) {
480	    if (!relayReplyTo) relayLoopGuard?.reopen(rt.target);
481	    sendRelay(rt.target, rt.text).catch((err) =>
482	      console.error(`[chat ${chatId}] sendRelay to ${rt.target} failed:`, err));
483	  }
484	  for (const rf of relayFileTokens) {
485	    sendRelayFile(rf.target, rf.path).catch((err) =>
486	      console.error(`[chat ${chatId}] sendRelayFile to ${rf.target} failed:`, err));
487	  }
488	  for (const rd of relayDelegateTokens) {
489	    if (isLocalSpecialist(rd.target)) {
490	      console.log(`[chat ${chatId}] dispatching to local specialist "${rd.target}" (id=${rd.payload.id})`);
491	      saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
492	        console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
493	      dispatchToSpecialist(rd.target, rd.payload, ctx.from?.id).then(async (result) => {
494	        console.log(`[chat ${chatId}] specialist "${rd.target}" returned: ${result.payload.status}, summary length=${result.payload.summary?.length ?? 0}`);
495	        saveArtifact(rd.payload.id, rd.target, rd.payload.goal, result.payload.status as any, result.payload.summary, result.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));
496	        const delegationCtx = await loadDelegationContext(rd.payload.id);
497	        const metaPrompt =
498	          delegationCtx +
499	          `[系統] Specialist "${rd.target}" 委派結果回傳\n` +
500	          `Status: ${result.payload.status}\n` +
501	          `Summary:\n${result.payload.summary}\n` +
502	          `[End specialist result]\n\n` +
503	          `請根據委派結果繼續回覆使用者。`;
504	        const userId = config.allowedUserIds[0] ?? chatId;
505	        const { runPrompt, sessions } = deps();
506	        const fakeCtx = {
507	          chat: { id: chatId, type: "private" as const },
508	          from: { id: userId, is_bot: false, first_name: rd.target },
509	          message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: metaPrompt },
510	          api: bot.api,
511	          reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
512	        } as unknown as Context;
513	        const s = await sessions.get(chatId, userId);
514	        try {
515	          await runPrompt(fakeCtx, s, metaPrompt, { kind: "meta" });
516	        } catch (runErr) {
517	          console.error(`[chat ${chatId}] specialist result injection failed:`, runErr);
518	        }
519	      }).catch((err) => {
520	        console.error(`[chat ${chatId}] specialist dispatch failed:`, err);
521	      });
522	    } else {
523	      if (!relayReplyTo) relayLoopGuard?.reopen(rd.target);
524	      if (session._lastUploadPath) {
525	        const attachmentPath = session._lastUploadPath;
526	        session._lastUploadPath = undefined;
527	        const caption = `${DELEGATE_PREFIX} ${JSON.stringify(rd.payload)}`;
528	        if (caption.length <= 1000) {
529	          sendRelayFile(rd.target, attachmentPath, caption).catch((err) =>
530	            console.error(`[chat ${chatId}] sendRelayFile (delegate attachment) to ${rd.target} failed:`, err));
531	        } else {
532	          sendRelayDelegate(rd.target, rd.payload)
533	            .then(() => sendRelayFile(rd.target, attachmentPath))
534	            .catch((err) =>
535	              console.error(`[chat ${chatId}] relay delegate + attachment fallback to ${rd.target} failed:`, err));
536	        }
537	      } else {
538	        sendRelayDelegate(rd.target, rd.payload).catch((err) =>
539	          console.error(`[chat ${chatId}] sendRelayDelegate to ${rd.target} failed:`, err));
540	      }
541	      if (!relayReplyTo) {
542	        saveDelegationContext(chatId, rd.payload.id, session).catch((err) =>
543	          console.error(`[chat ${chatId}] saveDelegationContext failed:`, err));
544	      }
545	    }
546	  }
547	  for (const rr of relayResultTokens) {
548	    sendRelayResult(rr.target, rr.payload).catch((err) =>
549	      console.error(`[chat ${chatId}] sendRelayResult to ${rr.target} failed:`, err));
550	    relayLoopGuard?.markDone(rr.target);
551	  }
552	  if (relayReplyTo && !relayTokens.some((rt) => rt.target === relayReplyTo)) {
553	    sendRelay(relayReplyTo, body).catch((err) =>
554	      console.error(`[chat ${chatId}] auto relay reply to ${relayReplyTo} failed:`, err));
555	  }
556	}
