558	// ─── Parallel delegate dispatch ─────────────────────────────────────────────
559	
560	export function dispatchParallelDelegates(
561	  chatId: number,
562	  bot: Bot,
563	  ctx: Context,
564	  tasks: ParallelTask[],
565	): void {
566	  const validTasks = tasks.filter((t) => isLocalSpecialist(t.target));
567	  const invalidTasks = tasks.filter((t) => !isLocalSpecialist(t.target));
568	  for (const inv of invalidTasks) {
569	    console.warn(`[chat ${chatId}] PARALLEL_DELEGATE unknown specialist: ${inv.target}`);
570	  }
571	  if (validTasks.length === 0) return;
572	
573	  console.log(`[chat ${chatId}] dispatching ${validTasks.length} parallel delegate(s): ${validTasks.map((t) => `${t.target}:${t.taskId}`).join(", ")}`);
574	  dispatchParallel(validTasks, ctx.from?.id).then(async (results) => {
575	    console.log(`[chat ${chatId}] parallel dispatch complete: ${results.map((r) => `${r.taskId}=${r.status}`).join(", ")}`);
576	    for (const r of results) {
577	      const task = validTasks.find((t) => t.taskId === r.taskId);
578	      saveArtifact(r.taskId, r.target, task?.payload.goal ?? "", r.status, r.summary, r.rawOutput).catch((e) => console.warn(`[chat ${chatId}] saveArtifact failed:`, e));
579	    }
580	    const lines = results.map((r) => {
581	      const statusIcon = r.status === "done" ? "✅" : r.status === "timeout" ? "⏱️" : "❌";
582	      return `[PARALLEL_RESULT:${r.taskId}] ${statusIcon} (${r.target}, ${r.status})\n${r.summary}`;
583	    });
584	    // Cross-check: when ≥2 specialists completed, ask main agent to
585	    // compare findings and flag contradictions before replying to user.
586	    const doneCount = results.filter((r) => r.status === "done").length;
587	    const crossCheckBlock = doneCount >= 2
588	      ? `\n\n[Cross-check 指引]\n` +
589	        `以上有 ${doneCount} 個 specialist 各自獨立完成了任務。回覆使用者前請：\n` +
590	        `1. 比對各結果之間是否有矛盾、衝突或不一致之處\n` +
591	        `2. 若有矛盾，明確指出哪些點衝突並給出你的判斷（採信哪個、為什麼）\n` +
592	        `3. 若無矛盾，整合各結果為統一回覆\n` +
593	        `[End cross-check]\n`
594	      : "";
595	    const metaPrompt =
596	      `[系統] 並行委派結果回傳（${results.length} 個任務全部完成）\n\n` +
597	      lines.join("\n\n---\n\n") + "\n\n" +
598	      `[End parallel results]` + crossCheckBlock + "\n\n" +
599	      `請根據以上結果繼續回覆使用者。`;
600	    const userId = config.allowedUserIds[0] ?? chatId;
601	    const { runPrompt, sessions } = deps();
602	    const fakeCtx = {
603	      chat: { id: chatId, type: "private" as const },
604	      from: { id: userId, is_bot: false, first_name: "parallel" },
605	      message: { message_id: 0, date: 0, chat: { id: chatId, type: "private" as const }, text: metaPrompt },
606	      api: bot.api,
607	      reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
608	    } as unknown as Context;
609	    const s = await sessions.get(chatId, userId);
610	    if (s.inflight) {
611	      console.log(`[chat ${chatId}] parallel result queued (session inflight)`);
612	      s._pendingMetaQueue.push({ ctx: fakeCtx, prompt: metaPrompt, opts: { kind: "meta" } });
613	    } else {
614	      try {
615	        await runPrompt(fakeCtx, s, metaPrompt, { kind: "meta" });
616	      } catch (err) {
617	        console.error(`[chat ${chatId}] parallel result injection failed:`, err);
618	      }
619	    }
620	  }).catch((err) => {
621	    console.error(`[chat ${chatId}] parallel dispatch failed:`, err);
622	  });
623	}
