810	
811	/**
812	 * Initialize the relay poller (called from main() during startup).
813	 */
814	export function initRelayPoller(bot: Bot): void {
815	  if (!config.relay) return;
816	  const relayConfig = config.relay;
817	  relayLoopGuard = new RelayLoopGuard({
818	    maxTurns: relayConfig.maxConsecutiveTurns,
819	    doneBlockMs: 300_000,
820	  });
821	  startRelayPoller(bot, relayConfig, async (msg) => {
822	    if (relayConfig.transport !== "telegram") ensurePollerRunning();
823	    if (process.env.RELAY_PAUSED === "true") return;
824	    const guard = relayLoopGuard;
825	    if (!guard) return;
826	    const parsedEarly = parseRelayPayload(msg.text);
827	    const isDelegation = parsedEarly?.type === "delegate";
828	    const decision = guard.allowIncoming(msg.from);
829	    if (decision.action === "blocked-done" && !isDelegation) {
830	      console.log(`[relay] done guard: skipping inject from "${msg.from}" until ${new Date(decision.until).toISOString()}`);
831	      const peer = msg.from;
832	      const chatId = relayConfig.groupChatId;
833	      const userId = config.allowedUserIds[0] ?? 0;
834	      const { runPrompt, sessions } = deps();
835	      sessions.get(chatId, userId).then((session) => {
836	        const fakeCtx = {
837	          chat: { id: chatId, type: "supergroup" as const },
838	          from: { id: userId, is_bot: false, first_name: peer },
839	          message: { message_id: 0, date: 0, chat: { id: chatId, type: "supergroup" as const }, text: "" },
840	          api: bot.api,
841	          reply: (text: string, extra?: any) => bot.api.sendMessage(chatId, text, extra),
842	        } as unknown as Context;
843	        const summaryPrompt =
844	          `[系統] 你剛才與「${peer}」的 relay 對話已結束（對方先發了 RELAY_DONE）。` +
845	          `請用一句話摘要這次 relay 對話的重點，然後呼叫 remember() 存下來。` +
846	          `格式範例：remember("[relay ${peer}] …摘要內容…")。` +
847	          `不需要回覆其他內容。`;
848	        runPrompt(fakeCtx, session, summaryPrompt, { kind: "meta", silent: true }).catch((err) => {
849	          console.error(`[relay] peer-done remember meta prompt failed:`, err);
850	        });
