1	/**
2	 * Specialist — local agent instances (same machine, stdio AcpClient).
3	 *
4	 * Config lives at AGENT_CONFIG_DIR/specialists.json. Each entry defines
5	 * a named specialist with its own CLI harness, working directory, and
6	 * user-data-dir for skill isolation.
7	 *
8	 * Flow:
9	 *   1. Bridge intercepts RELAY_DELEGATE token
10	 *   2. If target matches a specialist name → dispatch here (not relay)
11	 *   3. Spawn or reuse an AcpClient for that specialist
12	 *   4. Inject goal prompt → collect result → return ResultPayload
13	 */
14	import { readFile } from "node:fs/promises";
15	import { appendFile, mkdir } from "node:fs/promises";
16	import path from "node:path";
17	import { AcpClient, type AcpClientOptions, type SessionUpdate } from "./acpClient.js";
18	import type { DelegatePayload, ResultPayload } from "./relay.js";
19	import { config } from "./config.js";
20	import { buildSpecialistPreamble, getSpecialistScope } from "./specialist-create.js";
21	import { runEnrichment } from "./enrichment.js";
22	import { isEmbedRouterReady } from "./embed-router.js";
23	import { isWikiRetrievalReady } from "./wiki-retrieval.js";
24	import { isMemoryRecallReady } from "./memory-recall.js";
25	import { registerTask, updateTask, completeTask } from "./status-store.js";
26	import { broadcastSSE } from "./status-server.js";
27	
28	// ─── Config types ──────────────────────────────────────────────────────────
29	
30	export interface SpecialistHarness {
31	  command: string;
32	  args: string[];
33	}
34	
35	export interface SpecialistEntry {
36	  /** Display/lookup name — must match the target in RELAY_DELEGATE token. */
37	  name: string;
38	  /** CLI command + args to spawn the agent. */
39	  harness: SpecialistHarness;
40	  /** Working directory for the specialist session. */
41	  cwd: string;
42	  /** Extra env vars merged into the specialist process. */
43	  env?: Record<string, string>;
44	  /** MCP servers to inject via ACP session/new. */
45	  mcpServers?: any[];
46	  /** Max turns before force-stopping a delegation. Default 15. */
47	  maxTurns?: number;
48	  /** Timeout (ms) for the entire delegation. Default 600000 (10min). */
49	  timeoutMs?: number;
50	}
51	
52	export type SpecialistsConfig = SpecialistEntry[];
53	
54	// ─── Config loading ────────────────────────────────────────────────────────
55	
56	let loadedConfig: SpecialistsConfig = [];
57	let configPath = "";
58	
59	export function getSpecialists(): SpecialistsConfig {
60	  return loadedConfig;
61	}
62	
63	/** Check if a target name matches a local specialist. */
64	export function isLocalSpecialist(target: string): boolean {
65	  return loadedConfig.some((s) => s.name === target);
66	}
67	
68	/** Check if harness uses --agent flag (kiro-cli loads MCP servers from agent config). */
69	function harnessHasAgentFlag(entry: SpecialistEntry): boolean {
70	  return entry.harness.args.includes("--agent");
71	}
72	
73	/** Expand ${MEMORY_DIR} / ${AGENT_CONFIG_DIR} / ${BRIDGE_DIR} in specialist config strings. */
74	function expandVars(entry: SpecialistEntry): SpecialistEntry {
75	  const vars: Record<string, string> = {
76	    MEMORY_DIR: config.memoryDir,
77	    AGENT_CONFIG_DIR: path.dirname(configPath),
78	    BRIDGE_DIR: path.resolve(config.sessionCwd),
79	  };
80	  const replace = (s: string) =>
81	    s.replace(/\$\{(\w+)\}/g, (_, k) => vars[k] ?? `\${${k}}`);
82	  return {
83	    ...entry,
84	    cwd: replace(entry.cwd),
85	    harness: { command: entry.harness.command, args: entry.harness.args.map(replace) },
86	    env: entry.env
87	      ? Object.fromEntries(Object.entries(entry.env).map(([k, v]) => [k, replace(v)]))
88	      : undefined,
89	  };
90	}
91	
92	/** Load specialists.json from AGENT_CONFIG_DIR. Returns count loaded. */
93	export async function loadSpecialistsConfig(agentConfigDir: string): Promise<number> {
94	  configPath = path.join(agentConfigDir, "specialists.json");
95	  try {
96	    const raw = await readFile(configPath, "utf8");
97	    const parsed = JSON.parse(raw);
98	    if (!Array.isArray(parsed)) {
99	      console.warn(`[specialist] ${configPath} is not an array, ignoring`);
100	      loadedConfig = [];
101	      return 0;
102	    }
103	    loadedConfig = (parsed as SpecialistsConfig).map(expandVars);
104	    console.log(`[specialist] loaded ${loadedConfig.length} specialist(s) from ${configPath}`);
105	    return loadedConfig.length;
106	  } catch (err: any) {
107	    if (err.code === "ENOENT") {
108	      console.log(`[specialist] no config at ${configPath} — feature disabled`);
109	    } else {
110	      console.warn(`[specialist] failed to load ${configPath}:`, err.message);
111	    }
112	    loadedConfig = [];
113	    return 0;
114	  }
115	}
116	
117	// ─── Transcript persistence ────────────────────────────────────────────────
118	
119	const transcriptDir = path.join(config.memoryDir, "sessions");
120	
121	async function appendTranscript(name: string, role: "user" | "assistant", text: string): Promise<void> {
122	  const date = new Date().toISOString().slice(0, 10);
123	  const file = path.join(transcriptDir, `specialist-${name}-${date}.md`);
124	  await mkdir(transcriptDir, { recursive: true });
125	  const prefix = role === "user" ? "**User:**" : `**${name}:**`;
126	  const entry = `${prefix}\n${text}\n\n---\n\n`;
127	  await appendFile(file, entry, "utf8");
128	}
129	
130	// ─── Instance management ───────────────────────────────────────────────────
131	
132	interface LiveInstance {
133	  client: AcpClient;
134	  busy: boolean;
135	  sessionId: string;
136	}
137	
138	const instances = new Map<string, LiveInstance>();
139	
140	function getEntry(name: string): SpecialistEntry | undefined {
141	  return loadedConfig.find((s) => s.name === name);
142	}
143	
144	/** Close and remove a specialist instance. */
145	export function closeInstance(name: string): void {
146	  const inst = instances.get(name);
147	  if (inst) {
148	    inst.client.close();
149	    instances.delete(name);
150	    console.log(`[specialist:${name}] closed (task done)`);
151	  }
152	}
153	
154	/** Close a parallel instance by its unique instanceId. */
155	export function closeParallelInstance(instanceId: string): void {
156	  const inst = parallelInstances.get(instanceId);
157	  if (inst) {
158	    inst.client.close();
159	    parallelInstances.delete(instanceId);
160	    console.log(`[specialist:${instanceId}] parallel instance closed`);
161	  }
162	}
163	
164	/** Parallel instances — keyed by unique instanceId, not reused. */
165	const parallelInstances = new Map<string, LiveInstance>();
166	
167	/** Spawn a fresh instance (no reuse). Returns a unique instanceId. */
168	export async function spawnNew(name: string): Promise<{ instanceId: string; inst: LiveInstance }> {
169	  const entry = getEntry(name);
170	  if (!entry) throw new Error(`[specialist] unknown specialist: ${name}`);
171	
172	  const instanceId = `${name}-${Math.random().toString(16).slice(2, 6)}`;
173	
174	  const opts: AcpClientOptions = {
175	    command: entry.harness.command,
176	    args: [...entry.harness.args],
177	    cwd: path.resolve(entry.cwd),
178	    env: { MEMORY_DIR: config.memoryDir, ...entry.env },
179	    promptRetries: 2,
180	    promptRetryBaseMs: 1000,
181	  };
182	
183	  const client = new AcpClient(opts);
184	  client.on("stderr", (chunk) => {
185	    process.stderr.write(`[specialist:${instanceId}] ${chunk}`);
186	  });
187	  client.on("exit", (code) => {
188	    console.log(`[specialist:${instanceId}] process exited (code=${code})`);
189	    parallelInstances.delete(instanceId);
190	  });
191	
192	  // If harness uses --agent flag, kiro-cli loads MCP servers from its own
193	  // agent config — passing them again in session/new causes a crash.
194	  const mcpServers = harnessHasAgentFlag(entry) ? undefined : entry.mcpServers;
195	  const sessionId = await client.initializeAndCreateSession(opts.cwd, mcpServers);
196	  const inst: LiveInstance = { client, busy: false, sessionId };
197	  parallelInstances.set(instanceId, inst);
198	  console.log(`[specialist:${instanceId}] spawned (parallel), session=${sessionId}`);
199	  return { instanceId, inst };
200	}
201	
202	async function spawnOrReuse(name: string): Promise<LiveInstance> {
203	  const existing = instances.get(name);
204	  if (existing && !existing.client.isClosed) return existing;
205	
206	  // Clean up stale entry
207	  if (existing) instances.delete(name);
208	
209	  const entry = getEntry(name);
210	  if (!entry) throw new Error(`[specialist] unknown specialist: ${name}`);
211	
212	  const opts: AcpClientOptions = {
213	    command: entry.harness.command,
214	    args: [...entry.harness.args],
215	    cwd: path.resolve(entry.cwd),
216	    env: { MEMORY_DIR: config.memoryDir, ...entry.env },
217	    promptRetries: 2,
218	    promptRetryBaseMs: 1000,
219	  };
220	
221	  const client = new AcpClient(opts);
222	  client.on("stderr", (chunk) => {
223	    process.stderr.write(`[specialist:${name}] ${chunk}`);
224	  });
225	  client.on("exit", (code) => {
226	    console.log(`[specialist:${name}] process exited (code=${code})`);
227	    instances.delete(name);
228	  });
229	
230	  const sessionId = await client.initializeAndCreateSession(opts.cwd,
231	    harnessHasAgentFlag(entry) ? undefined : entry.mcpServers);
232	  const inst: LiveInstance = { client, busy: false, sessionId };
233	  instances.set(name, inst);
234	  console.log(`[specialist:${name}] spawned, session=${sessionId}`);
235	  return inst;
236	}
237	
238	// ─── Dispatch ──────────────────────────────────────────────────────────────
239	
240	export interface DispatchResult {
241	  payload: ResultPayload;
242	  /** Raw text chunks collected from the specialist's response. */
243	  rawOutput: string;
244	}
245	
246	/**
247	 * Dispatch a delegation to a local specialist.
248	 * Spawns/reuses the specialist, sends the goal prompt, collects the response,
249	 * and returns a structured ResultPayload.
250	 */
251	export async function dispatchToSpecialist(
252	  target: string,
253	  delegate: DelegatePayload,
254	  userId?: number,
255	): Promise<DispatchResult> {
256	  const entry = getEntry(target);
257	  if (!entry) throw new Error(`[specialist] unknown: ${target}`);
258	
259	  const inst = await spawnOrReuse(target);
260	  if (inst.busy) {
261	    return {
262	      payload: { id: delegate.id, status: "failed", summary: "Specialist is busy with another task" },
263	      rawOutput: "",
264	    };
265	  }
266	
267	  inst.busy = true;
268	  const maxTurns = delegate.maxTurns ?? entry.maxTurns ?? 15;
269	  const timeoutMs = entry.timeoutMs ?? 600_000;
270	
271	  // Register with status store
272	  registerTask({
273	    taskId: delegate.id,
274	    type: "specialist",
275	    specialist: target,
276	    goal: delegate.goal.slice(0, 100),
277	  });
278	
279	  // Build preamble from relevant topic shards
280	  const preamble = await buildSpecialistPreamble(target, userId ?? 0).catch(() => "");
281	
282	  // Run scoped enrichment based on the delegation goal
283	  const scope = await getSpecialistScope(target).catch(() => undefined);
284	  const enrichment = await runEnrichment(delegate.goal, userId ?? 0, undefined, scope).catch(() => "");
285	
286	  // Build the goal prompt
287	  const prompt = buildGoalPrompt(delegate, preamble, enrichment);
288	
289	  let output = "";
290	  const updateHandler = (u: SessionUpdate) => {
291	    const up = u.update;
292	    if (
293	      (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk") 
294	    ) {
295	      const content = up.content as { type?: string; text?: string } | undefined;
296	      if (content?.type === "text" && typeof content.text === "string") {
297	        output += content.text;
298	        const role = up.sessionUpdate === "agent_thought_chunk" ? "thought" : "agent";
299	        broadcastSSE(delegate.id, { type: "chunk", role, text: content.text });
300	      }
301	    }
302	  };
303	  inst.client.on("update", updateHandler);
304	
305	  try {
306	    // Multi-turn loop: keep prompting until agent says done or budget exhausted
307	    let turns = 0;
308	    let lastStopReason = "";
309	
310	    const deadline = Date.now() + timeoutMs;
311	
312	    while (turns < maxTurns && Date.now() < deadline) {
313	      turns++;
314	      updateTask(delegate.id, { turns, lastOutput: output.slice(-200) || undefined });
315	      broadcastSSE(delegate.id, { type: "status", status: "running", turns });
316	      const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";
317	
318	      const result = await Promise.race([
319	        inst.client.prompt(promptText),
320	        new Promise<never>((_, reject) =>
321	          setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
322	        ),
323	      ]);
324	
325	      lastStopReason = result.stopReason;
326	      // If agent stopped normally (end_turn), check if it needs more turns
327	      if (lastStopReason === "end_turn" || lastStopReason === "stop") break;
328	      // tool_use means agent is still working — loop for next turn
329	    }
330	
331	    // Extract summary from output (last 2000 chars as summary)
332	    const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";
333	
334	    const status: ResultPayload["status"] =
335	      Date.now() >= deadline ? "timeout" : "done";
336	
337	    completeTask(delegate.id, status, { lastOutput: summary.slice(0, 200) });
338	    broadcastSSE(delegate.id, { type: "status", status });
339	
340	    // Persist transcript for /memorytoskill
341	    appendTranscript(target, "user", prompt).catch(() => {});
342	    appendTranscript(target, "assistant", output).catch(() => {});
343	
344	    return {
345	      payload: { id: delegate.id, status, summary },
346	      rawOutput: output,
347	    };
348	  } catch (err: any) {
349	    const msg = err.message ?? String(err);
350	    const failStatus = msg.includes("timeout") ? "timeout" : "failed";
351	    completeTask(delegate.id, failStatus, { error: msg.slice(0, 200) });
352	    broadcastSSE(delegate.id, { type: "status", status: failStatus });
353	    return {
354	      payload: { id: delegate.id, status: "failed", summary: `Error: ${msg.slice(0, 500)}` },
355	      rawOutput: output,
356	    };
357	  } finally {
358	    inst.client.removeListener("update", updateHandler);
359	    inst.busy = false;
360	    closeInstance(target);
361	  }
362	}
363	
364	function buildGoalPrompt(d: DelegatePayload, preamble: string, enrichment?: string): string {
365	  let prompt = preamble;
366	  if (enrichment) prompt += enrichment;
367	  prompt += `[Delegation Task — id: ${d.id}]\n`;
368	  prompt += `Goal: ${d.goal}\n`;
369	  if (d.context) prompt += `Context: ${d.context}\n`;
370	  prompt += `\nComplete this task. When done, summarize what you accomplished.`;
371	  return prompt;
372	}
373	
374	// ─── Parallel Dispatch ─────────────────────────────────────────────────────
375	
376	export interface ParallelTask {
377	  taskId: string;
378	  target: string;
379	  payload: DelegatePayload;
380	}
381	
382	export interface ParallelResult {
383	  taskId: string;
384	  target: string;
385	  status: "done" | "timeout" | "failed";
386	  summary: string;
387	  rawOutput: string;
388	}
389	
390	/**
391	 * Dispatch multiple delegations in parallel. Each gets its own fresh instance.
392	 * Returns after all settle (Promise.allSettled).
393	 */
394	export async function dispatchParallel(
395	  tasks: ParallelTask[],
396	  userId?: number,
397	): Promise<ParallelResult[]> {
398	  const promises = tasks.map(async (task): Promise<ParallelResult> => {
399	    const entry = getEntry(task.target);
400	    if (!entry) {
401	      return { taskId: task.taskId, target: task.target, status: "failed", summary: `Unknown specialist: ${task.target}`, rawOutput: "" };
402	    }
403	
404	    let instanceId = "";
405	    try {
406	      registerTask({
407	        taskId: task.taskId,
408	        type: "parallel_delegate",
409	        specialist: task.target,
410	        goal: task.payload.goal.slice(0, 100),
411	      });
412	      const spawned = await spawnNew(task.target);
413	      instanceId = spawned.instanceId;
414	      const inst = spawned.inst;
415	
416	      const maxTurns = task.payload.maxTurns ?? entry.maxTurns ?? 15;
417	      const timeoutMs = entry.timeoutMs ?? 600_000;
418	
419	      const preamble = await buildSpecialistPreamble(task.target, userId ?? 0).catch(() => "");
420	      const scope = await getSpecialistScope(task.target).catch(() => undefined);
421	      const enrichment = await runEnrichment(task.payload.goal, userId ?? 0, undefined, scope).catch(() => "");
422	      const prompt = buildGoalPrompt(task.payload, preamble, enrichment);
423	
424	      let output = "";
425	      const updateHandler = (u: SessionUpdate) => {
426	        const up = u.update;
427	        if (
428	          (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk")
429	        ) {
430	          const content = up.content as { type?: string; text?: string } | undefined;
431	          if (content?.type === "text" && typeof content.text === "string") {
432	            output += content.text;
433	            const role = up.sessionUpdate === "agent_thought_chunk" ? "thought" : "agent";
434	            broadcastSSE(task.taskId, { type: "chunk", role, text: content.text });
435	          }
436	        }
437	      };
438	      inst.client.on("update", updateHandler);
439	
440	      try {
441	        let turns = 0;
442	        const deadline = Date.now() + timeoutMs;
443	
444	        while (turns < maxTurns && Date.now() < deadline) {
445	          turns++;
446	          const promptText = turns === 1 ? prompt : "[系統] 繼續執行，完成後在回覆中說明結果。";
447	          const result = await Promise.race([
448	            inst.client.prompt(promptText),
449	            new Promise<never>((_, reject) =>
450	              setTimeout(() => reject(new Error("timeout")), Math.max(1000, deadline - Date.now())),
451	            ),
452	          ]);
453	          if (result.stopReason === "end_turn" || result.stopReason === "stop") break;
454	        }
455	
456	        const summary = output.length > 2000 ? output.slice(-2000) : output || "(no output)";
457	        const status: ParallelResult["status"] = Date.now() >= deadline ? "timeout" : "done";
458	
459	        completeTask(task.taskId, status, { lastOutput: summary.slice(0, 200) });
460	
461	        appendTranscript(task.target, "user", prompt).catch(() => {});
462	        appendTranscript(task.target, "assistant", output).catch(() => {});
463	
464	        return { taskId: task.taskId, target: task.target, status, summary, rawOutput: output };
465	      } finally {
466	        inst.client.removeListener("update", updateHandler);
467	        closeParallelInstance(instanceId);
468	      }
469	    } catch (err: any) {
470	      if (instanceId) closeParallelInstance(instanceId);
471	      const msg = (err.message ?? String(err)).slice(0, 500);
472	      completeTask(task.taskId, "failed", { error: msg.slice(0, 200) });
473	      return { taskId: task.taskId, target: task.target, status: "failed", summary: `Error: ${msg}`, rawOutput: "" };
474	    }
475	  });
476	
477	  const settled = await Promise.allSettled(promises);
478	  return settled.map((s, i) =>
479	    s.status === "fulfilled"
480	      ? s.value
481	      : { taskId: tasks[i].taskId, target: tasks[i].target, status: "failed" as const, summary: `Unexpected: ${s.reason}`, rawOutput: "" },
482	  );
483	}
484	
485	// ─── Cleanup ───────────────────────────────────────────────────────────────
486	
487	export async function shutdownAllSpecialists(): Promise<void> {
488	  for (const [name, inst] of instances) {
489	    console.log(`[specialist:${name}] shutting down...`);
490	    await inst.client.close();
491	  }
492	  instances.clear();
493	  proxyState.clear();
494	}
495	
496	// ─── Transparent Proxy Mode ────────────────────────────────────────────────
497	
498	const PROXY_DONE_RE = /<<PROXY_DONE>>/i;
499	
500	interface ProxySession {
501	  specialistName: string;
502	  /** Conversation history for end-of-proxy summary. */
503	  history: { role: "user" | "assistant"; text: string }[];
504	  startedAt: number;
505	  lastActivity: number;
506	  /** Facts already injected via enrichment — dedup across turns. */
507	  injectedFacts: Set<string>;
508	  /** Total chars sent to specialist (preamble + enrichment + user text). */
509	  charsIn: number;
510	  /** Total chars received from specialist. */
511	  charsOut: number;
512	}
513	
514	const proxyState = new Map<number, ProxySession>();
515	
516	/** Check if a chatId is currently in proxy mode. */
517	export function isProxyActive(chatId: number): boolean {
518	  return proxyState.has(chatId);
519	}
520	
521	/** Get the active proxy specialist name for a chatId. */
522	export function getProxyTarget(chatId: number): string | undefined {
523	  return proxyState.get(chatId)?.specialistName;
524	}
525	
526	/** Get cumulative char stats for the active proxy session. */
527	export function getProxyStats(chatId: number): { charsIn: number; charsOut: number } | undefined {
528	  const ps = proxyState.get(chatId);
529	  return ps ? { charsIn: ps.charsIn, charsOut: ps.charsOut } : undefined;
530	}
531	
532	/** Enter proxy mode: subsequent user messages go directly to this specialist. */
533	export function startProxy(chatId: number, specialistName: string): void {
534	  proxyState.set(chatId, {
535	    specialistName,
536	    history: [],
537	    startedAt: Date.now(),
538	    lastActivity: Date.now(),
539	    injectedFacts: new Set(),
540	    charsIn: 0,
541	    charsOut: 0,
542	  });
543	  console.log(`[specialist:proxy] chat ${chatId} → proxy to "${specialistName}"`);
544	}
545	
546	/** Exit proxy mode. Returns the conversation history for summary injection. */
547	export function endProxy(chatId: number): ProxySession | undefined {
548	  const session = proxyState.get(chatId);
549	  proxyState.delete(chatId);
550	  if (session) {
551	    console.log(`[specialist:proxy] chat ${chatId} exited proxy (${session.history.length} exchanges)`);
552	    closeInstance(session.specialistName);
553	  }
554	  return session;
555	}
556	
557	/** Register a callback for idle timeout auto-exit. */
558	/**
559	 * Send a user message to the proxied specialist and collect the response.
560	 * Returns the raw output text (caller is responsible for sending to Telegram
561	 * and extracting memory tokens).
562	 */
563	export async function promptProxy(
564	  chatId: number,
565	  text: string,
566	  onChunk?: (currentOutput: string) => void,
567	  userId?: number,
568	): Promise<{ output: string; stopReason: string; proxyDone: boolean }> {
569	  const ps = proxyState.get(chatId);
570	  if (!ps) throw new Error("[specialist:proxy] no active proxy for this chat");
571	
572	  const inst = await spawnOrReuse(ps.specialistName);
573	
574	  // First prompt: prepend preamble + instruction so specialist knows about PROXY_DONE
575	  const isFirst = ps.history.length === 0;
576	  let prompt: string;
577	  if (isFirst) {
578	    const preamble = await buildSpecialistPreamble(ps.specialistName, userId ?? 0, { proxy: true }).catch(() => "");
579	    // Run scoped enrichment for the first message too
580	    const scope = await getSpecialistScope(ps.specialistName).catch(() => undefined);
581	    console.log(`[specialist:proxy] enrichment scope for ${ps.specialistName}:`, JSON.stringify(scope ?? null));
582	    console.log(`[specialist:proxy] subsystem ready: embed=${isEmbedRouterReady()}, wiki=${isWikiRetrievalReady()}, recall=${isMemoryRecallReady()}`);
583	    const enrichment = await runEnrichment(text, userId ?? 0, ps.injectedFacts, scope).catch((e) => { console.warn("[specialist:proxy] enrichment error:", e); return ""; });
584	    console.log(`[specialist:proxy] enrichment result length: ${enrichment.length}${enrichment.length > 0 ? " (has content)" : " (empty)"}`);
585	    prompt = `${preamble}[System] You are in a proxy conversation with the user. Do NOT append <<PROXY_DONE>> unless the user explicitly ends the conversation (says goodbye, "沒了", "就這樣", "thanks that's all", etc.). Simply answering a question does NOT mean the conversation is over — always assume follow-ups.\n\n${enrichment}User: ${text}`;
586	  } else {
587	    // Subsequent turns: still run scoped enrichment (dynamic per-turn)
588	    const scope = await getSpecialistScope(ps.specialistName).catch(() => undefined);
589	    console.log(`[specialist:proxy] turn enrichment scope:`, JSON.stringify(scope ?? null));
590	    const enrichment = await runEnrichment(text, userId ?? 0, ps.injectedFacts, scope).catch((e) => { console.warn("[specialist:proxy] turn enrichment error:", e); return ""; });
591	    console.log(`[specialist:proxy] turn enrichment length: ${enrichment.length}`);
592	    prompt = enrichment ? `${enrichment}${text}` : text;
593	  }
594	
595	  let output = "";
596	  const updateHandler = (u: SessionUpdate) => {
597	    const up = u.update;
598	    if (
599	      (up.sessionUpdate === "agent_message_chunk" || up.sessionUpdate === "agent_thought_chunk")
600	    ) {
601	      const content = up.content as { type?: string; text?: string } | undefined;
602	      if (content?.type === "text" && typeof content.text === "string") {
603	        output += content.text;
604	        onChunk?.(output);
605	      }
606	    }
607	  };
608	  inst.client.on("update", updateHandler);
609	
610	  try {
611	    const result = await inst.client.prompt(prompt);
612	    ps.charsIn += prompt.length;
613	    ps.charsOut += output.length;
614	    ps.history.push({ role: "user", text });
615	    ps.history.push({ role: "assistant", text: output });
616	    ps.lastActivity = Date.now();
617	    // Persist transcript for /memorytoskill
618	    appendTranscript(ps.specialistName, "user", text).catch(() => {});
619	    appendTranscript(ps.specialistName, "assistant", output).catch(() => {});
620	    // Detect <<PROXY_DONE>> — specialist signals it's finished
621	    const proxyDone = PROXY_DONE_RE.test(output);
622	    const cleanOutput = output.replace(PROXY_DONE_RE, "").trim();
623	    return { output: cleanOutput, stopReason: result.stopReason, proxyDone };
624	  } finally {
625	    inst.client.removeListener("update", updateHandler);
626	  }
627	}
628	
629	/** Build a summary of the proxy conversation for injection into main agent. */
630	export function buildProxySummary(session: ProxySession): string {
631	  const lines: string[] = [];
632	  const count = Math.floor(session.history.length / 2);
633	  // Keep last 5 exchanges max for summary
634	  const recent = session.history.slice(-10);
635	  for (const h of recent) {
636	    const prefix = h.role === "user" ? "User" : session.specialistName;
637	    const truncated = h.text.length > 300 ? h.text.slice(0, 300) + "…" : h.text;
638	    lines.push(`${prefix}: ${truncated}`);
639	  }
640	  return (
641	    `[系統] Specialist "${session.specialistName}" proxy 結束（共 ${count} 輪對話）\n` +
642	    `以下是最近的對話摘要：\n` +
643	    lines.join("\n") + "\n" +
644	    `[End proxy summary]\n\n` +
645	    `使用者已切回跟你對話。如果 specialist 的工作有後續，請接續處理。`
646	  );
647	}
